beginner_examples.query:
try {
  session.startTransaction()
  // operations
  session.commitTransaction()
} catch (err) {
  session.abortTransaction()
  throw err
} finally {
  session.endSession()
}

result = session.commitTransaction()
if (result.ok === 1) { // success
} else { // failure
  session.abortTransaction()
}

advanced_examples.query:
maxRetries = 3
for (i = 0; i < maxRetries; i++) {
  try {
    session.startTransaction()
    // operations
    session.commitTransaction()
    break
  } catch (err) {
    if (err.transientError) {
      session.abortTransaction()
      // retry
    } else {
      throw err
    }
  }
}
